}

// Ensure the parsed value is an object
if (
    typeof classification !== "object" ||
    classification === null ||
    Array.isArray(classification)
) {
    throw new Error("❌ AI output is not a JSON object.");
}

// Required fields
if (!Object.prototype.hasOwnProperty.call(classification, "category")) {
    throw new Error("❌ Missing 'category' field.");
}

if (!Object.prototype.hasOwnProperty.call(classification, "folder")) {
    throw new Error("❌ Missing 'folder' field.");
}

// Type validation
if (typeof classification.category !== "string") {
    throw new Error("❌ 'category' must be a string.");
}

if (typeof classification.folder !== "string") {
    throw new Error("❌ 'folder' must be a string.");
}

// Valid category → folder mapping
const folderMap = {
    Work: "Work",
    Personal: "Personal",
    Finance: "Finance",
    Promotions: "Promotions",
    Spam: "Spam"
};

// Validate category
if (!Object.prototype.hasOwnProperty.call(folderMap, classification.category)) {
    throw new Error(
        `❌ Invalid category: ${classification.category}`
    );
}

// Validate folder
const expectedFolder = folderMap[classification.category];

if (classification.folder !== expectedFolder) {
    throw new Error(
        `❌ Folder mismatch. Expected '${expectedFolder}', got '${classification.folder}'.`
    );
}

// Success
return [{
    json: {
        ...data,

        aiClassification: classification,

        testResults: {
            ...(data.testResults ?? {}),
